using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF Core 9 renamed the discriminator JSON property
            // from "Discriminator" to "$type". Keep the old name so existing documents
            // and raw SQL queries (WHERE c.Discriminator = 'Blog') still work.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF Core 9 changed the synthesized resource-id from
            // "{Discriminator}|{Key}" to just "{Key}". Preserve the old format so
            // existing documents (e.g. id = "Blog|1") remain accessible.
            entity.Property("__id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3: HasIndex() now throws for Cosmos entities instead
            // of being silently ignored. The call has been removed.
            // REMOVED: entity.HasIndex(b => b.Name);
        });
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format: "{Discriminator}|{Key}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString()
            ?? entry.Metadata.ShortName();
        var key = entry.Property("Id").CurrentValue?.ToString();
        return $"{discriminator}|{key}";
    }
}

